// Extract IDs from webhook body - handle both body shapes
// n8n webhook v2 may nest as body.narrative_id or body.$json.narrative_id
const raw = $('Narrative Request').first().json;
const body = raw.body || {};
const payload = body.$json || body;

const narrative_id = payload.narrative_id;
const grant_id = payload.grant_id;

if (!narrative_id || !grant_id) {
  return [{
    json: {
      error: true,
      message: `Missing IDs. narrative_id: ${narrative_id}, grant_id: ${grant_id}. Raw body keys: ${Object.keys(body).join(', ')}`,
    }
  }];
}

return [{
  json: { narrative_id, grant_id }
}];

// Combine narrative + grant into a single object for AI customization
const narrative = $('Get Narrative').first().json;
const grant = $('Get Grant').first().json;

if (!narrative || !narrative.id) {
  return [{
    json: {
      error: true,
      message: 'Narrative not found for the given narrative_id',
    }
  }];
}

if (!grant || !grant.id) {
  return [{
    json: {
      error: true,
      message: 'Grant not found for the given grant_id',
    }
  }];
}

return [{
  json: {
    narrative_id: narrative.id,
    org_id: narrative.org_id,
    section_id: narrative.category || 'general',
    section_name: narrative.title,
    base_content: narrative.content,
    word_limit: narrative.metadata?.word_count || 250,
    grantContext: {
      grantId: grant.id,
      org_id: grant.org_id,
      grant_title: grant.title,
      grant_description: grant.description,
      funder_name: grant.funder_name,
      deadline: grant.deadline,
      amount: grant.amount,
    },
    is_fallback: false
  }
}];

