// Format and return the customized narrative
const sectionInfo = $('Prepare Context').first().json;
const aiResponse = $input.first().json;

const customizedText = aiResponse.message?.content || aiResponse.text || '';

return [{
  json: {
    success: true,
    narrative_id: sectionInfo.narrative_id,
    grant_id: sectionInfo.grantContext.grantId,
    section_id: sectionInfo.section_id,
    section_name: sectionInfo.section_name,
    customized_content: customizedText.trim(),
    word_count: customizedText.trim().split(/\s+/).length,
    word_limit: sectionInfo.word_limit,
    grant_title: sectionInfo.grantContext.grant_title || 'general',
    funder_name: sectionInfo.grantContext.funder_name || 'unknown',
    generatedAt: new Date().toISOString()
  }
}];
